import React from "react";
import { View } from "react-native";
import NewFeed from "~/common/components/major/NewFeed";
import Pagination from "~/common/components/major/Pagination";
import TitleList from "~/common/components/major/TitlesList";
import { readBookTitlesAsync } from "~/utils/api/firebase";
import { actionData, initialData, reducerData } from "~/utils/reducers/data";

export default function Home() {
  const [state, dispatch] = React.useReducer(reducerData, initialData);

  const downloadData = React.useCallback(async () => {
    const data = await readBookTitlesAsync();
    dispatch(actionData.setData(data));
  }, []);

  React.useEffect(() => {
    downloadData();
  }, []);

  const setIndex = React.useCallback((id) => {
    dispatch(actionData.setCurrentPage(id));
  }, []);

  return (
    <View style={{ flex: 1 }}>
      <TitleList data={state.data} />
      <NewFeed
        currentIndex={state.currentPage}
        currentRoute={"Home"}
        data={state.currentPageData}
        ListHeaderComponent={
          <Pagination
            currentPage={state.currentPage}
            onPageChange={setIndex}
            pageCount={5}
            pageSize={10}
            dataLength={state.data.length}
          />
        }
      />
    </View>
  );
}
