import { Link } from "@react-navigation/native";
import React from "react";
import useBurmese from "~/utils/hooks/useBurmese";

export default React.memo(function TitleList({ data }) {
  const renderItem = React.useCallback(
    (item, index) => (
      <Title title={item} key={item + index} index={index + 1} />
    ),
    []
  );

  const modifyData = React.useMemo(() => data.map((e) => e.title), [data]);

  return (
    <div
      className="offcanvas offcanvas-start bg-dark"
      tabIndex="-1"
      id="offcanvas"
      aria-labelledby="offcanvasLabel"
      style={{ zIndex: 999999 }}
    >
      <div className="offcanvas-header">
        <h5 className="offcanvas-title" id="offcanvasLabel">
          Title Lists
        </h5>
        <button
          type="button"
          className="btn-close text-reset"
          data-bs-dismiss="offcanvas"
          aria-label="Close"
        ></button>
      </div>
      <div className="offcanvas-body">{modifyData.map(renderItem)}</div>
    </div>
  );
});

const Title = React.memo(({ title, index }) => {
  const mmTitle = useBurmese(title);

  return (
    <Link to={{ screen: "Post", params: { title: title } }}>
      <div className="text-decoration-none text-left text-light p-2">
        {index}. {mmTitle}
      </div>
    </Link>
  );
});
