import React from "react";

const usePagination = ({ pageSize, pageCount, dataLength, currentPage }) => {
  const maxPageNumber = React.useMemo(
    () => Math.ceil(dataLength / pageSize),
    [dataLength, pageSize]
  );

  const shouldShowLeftDots = React.useMemo(
    () => currentPage > 5,
    [currentPage]
  );

  const shouldShowRightDots = React.useMemo(
    () => currentPage <= maxPageNumber - pageCount,
    [currentPage, maxPageNumber, pageCount]
  );

  const shouldShowPrev = React.useMemo(() => currentPage !== 1, [currentPage]);

  const shouldShowNext = React.useMemo(
    () => currentPage !== maxPageNumber,
    [currentPage, maxPageNumber]
  );

  const paginationRange = React.useMemo(() => {
    const start = Math.floor((currentPage - 1) / pageCount) * pageCount;

    return new Array(pageCount).fill().map((_, i) => start + i + 1);
  }, [currentPage, pageCount]);

  return {
    paginationRange,
    shouldShowPrev,
    shouldShowNext,
    shouldShowLeftDots,
    shouldShowRightDots,
    maxPageNumber,
  };
};

export default function Pagination({
  onPageChange,
  currentPage = 1,
  pageSize = 20,
  dataLength,
  pageCount = 5,
  className = "mb-2 d-flex flex-row align-items-center justify-content-center flex-wrap",
}) {
  const pagination = usePagination({
    pageSize,
    pageCount,
    dataLength,
    currentPage,
  });

  const onNext = React.useCallback(
    () => onPageChange(currentPage + 1),
    [onPageChange, currentPage]
  );

  const onPrevious = React.useCallback(
    () => onPageChange(currentPage - 1),
    [currentPage, onPageChange]
  );

  const onChange = React.useCallback(
    (e) => onPageChange(Number(e.target.textContent)),
    [onPageChange]
  );

  const renderItem = React.useCallback(
    (item, index) => (
      <Btn
        key={index}
        active={currentPage === item}
        value={item}
        onClick={onChange}
      />
    ),
    [currentPage]
  );

  if (dataLength === 0 || currentPage === 0) return null;

  return (
    <div className={className}>
      {pagination.shouldShowPrev && <Btn value={"Prev"} onClick={onPrevious} />}
      {pagination.shouldShowLeftDots && (
        <>
          <Btn value={"1"} onClick={onChange} />
          <Dots />
        </>
      )}

      {pagination.paginationRange.map(renderItem)}

      {pagination.shouldShowRightDots && (
        <>
          <Dots />
          <Btn value={pagination.maxPageNumber} onClick={onChange} />
        </>
      )}
      {pagination.shouldShowNext && <Btn value={"Next"} onClick={onNext} />}
    </div>
  );
}

const Dots = () => <span className="px-3 text-primary">...</span>;

const Btn = ({ value, className, onClick, active }) => (
  <button
    onClick={onClick}
    className={`btn mb-2 ${
      active ? "btn-primary" : "border border-1 border-primary text-primary"
    } ${className} me-1`}
    type="button"
  >
    {value}
  </button>
);
